import{_ as i,o as l,c as r,a4 as e}from"./chunks/framework.EYT3XhWU.js";const g=JSON.parse('{"title":"歧义句辨析","description":"","frontmatter":{},"headers":[],"relativePath":"行测/言语理解/歧义句辨析.md","filePath":"行测/言语理解/歧义句辨析.md"}'),t={name:"行测/言语理解/歧义句辨析.md"};function s(a,o,n,p,b,d){return l(),r("div",null,[...o[0]||(o[0]=[e('<h1 id="歧义句辨析" tabindex="-1">歧义句辨析 <a class="header-anchor" href="#歧义句辨析" aria-label="Permalink to “歧义句辨析”">​</a></h1><p>字数: 2272 字 时长: 9 分钟 <strong>VIP文档</strong></p><ol><li>深圳、上海、吉林、山东等省市曾考查歧义句，难度一般，需逐条分析。</li></ol><h2 id="一、歧义句的类型" tabindex="-1">一、歧义句的类型 <a class="header-anchor" href="#一、歧义句的类型" aria-label="Permalink to “一、歧义句的类型”">​</a></h2><blockquote><p>歧义句是指一个句子在特定语境下可能被理解为两种或多种不同的含义，导致语义不明确的现象。歧义的产生通常源于词汇、语法结构、语境或语音（如多音字）的模糊性。</p></blockquote><ol><li><p>1、语汇歧义</p><p>：词有不同的词性，可做名词或者动词；词语本身有多个含义；最后导致句子意义不确定。</p><ol><li><code>例1</code>：我们家门没锁。可理解为“门没有上锁”；也可理解为“门没有锁头”</li><li><code>例2</code>：我要炒肉丝。可理解为“炒”这个动作，也可理解为“炒肉丝”这个菜</li><li><code>例3</code>：他原来住这里。“原来”可理解为“以前”，也可理解为“竟然”</li></ol></li><li><p><strong>2、语法歧义</strong>：</p><ol><li><code>例1</code>：放弃美丽的女人让人心碎。让人心碎的是“女人”还是“放弃美丽的女人”这件事。对象不明</li><li><code>例2</code>：某高层嘱咐几个法院的领导，一定要让这起案件销声匿迹。可理解为“几个领导”，也可理解为“几个法院”。修饰不清</li><li><code>例3</code>：老王的笑话讲不完。可理解为“他能讲的笑话”，也可理解为“关于他的笑话”。关系不清</li><li><code>例4</code>：老李看到老王带着他的老婆出去了。不知道是老李的老婆还是老王的老婆。指代不明</li><li><code>例5</code>：上岸村通知说，让村民本月15日前去汇报。“前去”可理解为“15日之前去”，也可理解为“15日当天前往”。语义关系不明</li><li><code>例6</code>：鸡不吃了。到底是鸡不吃（东西）了还是（人）不吃鸡了。施受关系不明：动作的发出者（施事）和承受者（受事）关系不清。</li></ol></li><li><p><strong>3、停顿歧义</strong>：停顿在不同的位置具有不一样的意思。</p><ol><li><code>例1</code>：山上的水，我们留给晚上来的人喝。晚/上来的/人，指“山上晚了的人”；晚上/来的/人，指“夜晚上山的人”</li><li><code>例2</code>：发展经济学的理论渊源是人类关于推进社会经济快速发展的思想。发展/经济学的理论渊源，指发展“经济学”学科的理论；发展经济学/的理论渊源，指“发展经济学”这门经济学的理论</li><li><code>例3</code>：不适当地浇水施肥。是“不/适当地浇水施肥 （完全不做）”还是“不适当地/浇水施肥 （做了，但方式不对）”</li></ol></li><li><p><strong>4、语音歧义</strong>：口语中因发音相同而引发歧义。比如重音、多音</p><ol><li><code>例1</code>：他终于想起来了。当重音为“想”时，即想到事情；当重音为“起来“时，即起来这个动作</li><li><code>例2</code>：到2019年年底，厂里还欠款3000万元。这里的“还”可以读作“huan欠款”或“hai欠款”</li></ol></li></ol><h2 id="二、随笔练习" tabindex="-1">二、随笔练习 <a class="header-anchor" href="#二、随笔练习" aria-label="Permalink to “二、随笔练习”">​</a></h2><p><strong>例1</strong>：（2018深圳）下列各项中，没有歧义的一项是：</p><ol><li>A. 研究员到这里工作才一个月，好多人还不认识。</li><li>B. 演出期间，不少人遗憾地在剧场门口等着退票。</li><li>C. 他走了一个多钟头了。</li><li>D. 我看见他高兴得跳了起来。</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">A项，“好多人还不认识”可以理解为“研究员不认识其他人”，也可以理解为“其他人不认识研究员”，存在歧义，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项，没有歧义，当选；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项，“走”可以理解为走路，也可理解为离开，还可以理解为去世，“他走了一个多钟头了”存在歧义，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项，“高兴得跳了起来”的主语不能确定是“我”还是“他”，存在歧义，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为B。</li></ol></details><p><strong>例2</strong>：（2014上海）没有歧义的是__________。</p><ol><li>A. 谁都看不上</li><li>B. 照片放大了一点</li><li>C. 吃多少就吃多少</li><li>D. 我明天坐飞机回家</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">A项，既可以理解为“这个人看不上别人”，也可以理解为“大家都看不上这个人”，存在歧义，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项，既可以理解为“原来照片小，现在放大之后的尺寸达到了要求”，也可以理解为“照片放得过大，不符合要求”，存在歧义，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项，既可以将“多少”理解为一个名词，表示数量的大小，句子意思为“能吃多少就吃多少”，也可以把“多”理解为副词，修饰“少”，句子意思为“尽可能地少吃”，存在歧义，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项，句意明确，没有歧义，当选。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为D。</li></ol></details><p><strong>例3</strong>：（2018上海执法）下列各项中，没有歧义的一项是：</p><ol><li>A. 研究员到这里工作才一个月，好多人还不认识。</li><li>B. 演出期间，不少人遗憾地在剧场门口等着退票。</li><li>C. 他走了一个多钟头了。</li><li>D. 我看见他高兴得跳了起来。</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">A项，“好多人还不认识”可以理解为“研究员不认识其他人”，也可以理解为“其他人不认识研究员”，存在歧义，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项，没有歧义，当选；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项，“走”可以理解为走路，也可理解为离开，还可以理解为去世，“他走了一个多钟头了”存在歧义，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项，我看见/他高兴地跳了起来“他跳”；我看见他/高兴地跳了起来“我跳”，存在歧义，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为B。</li></ol></details><p><strong>例4</strong>：（2015河北选调）下列句子没有歧义、表述准确的一项是：</p><ol><li>A. 如果你能抽出宝贵时间，亲自参加我们的婚礼，那是我们求之不得的。</li><li>B. 老人80岁的时候，还记得哥哥参加学生运动时对自己的评价：一个温情主义者。</li><li>C. 我看见他很高兴，和他聊起了很快就要举行的国庆晚会的筹备情况。</li><li>D. 入秋以来，北京和河北的部分地区接连下了两场雨。</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">B项中“自己”，到底是“我”还是”哥哥“，指代不明，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项中“我”高兴还是“他”高兴，表义不明，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项中“北京和河北的部分地区”是指“北京全部，河北的部分地区”还是“北京的部分地区和河北的部分地区”，表义不明，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为A。</li></ol></details><p><strong>例5</strong>：（2015河北选调）下列句子中，没有歧义的一句是：</p><ol><li>A. 伊朗的“核武”问题，已引起美国总统奥巴马的密切关注。对此，美国有的国际问题专家则表示乐观</li><li>B. “依我看，这个考点最需要引起重视。”张老师补充道</li><li>C. 我在楼顶上栽的几盆花，长得枝繁叶茂</li><li>D. 厂长再次强调：“这个面子还是要的。”</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">A项“对此”的“此”指代不明，既可指“伊朗的核武问题”也可指“奥巴马的密切关注”，存在歧义；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项“考点”既可以指考查的知识点，也可指考试的地点，有歧义；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项“面子”既可理解为“物体的表面”，也可理解为“情面”，存在歧义；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项没有歧义。</li></ol></details><p><strong>例6</strong>：（2018上海事业单位）下列语句有歧义的是（ ）。</p><ol><li>A. 你到底是否认真听取了我的意见？</li><li>B. 究竟谁允许你到处乱倒建筑垃圾的？</li><li>C. 莫非你也认为这件事我彻底做错了？</li><li>D. 难道我老得连你也认不出来了吗？</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">A项、B项、C项表述均无歧义，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项：第一种：难道我老得（<code style="box-sizing:border-box;font-family:-apple-system, system-ui, &quot;Segoe UI&quot;, Roboto, Ubuntu, Cantarell, &quot;Noto Sans&quot;, sans-serif, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei&quot;, Arial;font-size:14px;width:unset;color:rgb(155, 133, 245);border-radius:4px;padding:3px 6px;background-color:rgba(101, 117, 133, 0.16);transition:color 0.25s, background-color 0.5s;">糊涂了</code>）/连你也认不出来了吗？（意思是：我认不出你）。第二种：难道我老得（<code style="box-sizing:border-box;font-family:-apple-system, system-ui, &quot;Segoe UI&quot;, Roboto, Ubuntu, Cantarell, &quot;Noto Sans&quot;, sans-serif, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei&quot;, Arial;font-size:14px;width:unset;color:rgb(155, 133, 245);border-radius:4px;padding:3px 6px;background-color:rgba(101, 117, 133, 0.16);transition:color 0.25s, background-color 0.5s;">变化太大</code>）/连你/也认不出来了吗？（意思是：你认不出我）存在歧义；。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为D。</li></ol></details><p><strong>例7</strong>：（2019内蒙古通辽招聘）下列没有歧义的句子是（ ）。</p><ol><li>A. 我看见李浩扶着一位老人走下车来，手里拿着一只皮包</li><li>B. 李煜认为杜甫有浓厚的门第等级观念的观点是值得商榷的</li><li>C. 我校举办的数学、物理两个短训班开设了农用数学、农业机电课程</li><li>D. 括号里的话如果是注释整个句子的，这种括号叫句外括号；句外括号要放在句末的标点之后</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">A项，“手里拿着一只皮包”的主语不明确，无法确定是李浩还是老人；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项，本句中无法确定是谁的“观点”，可能是李煜的，也可能是杜甫的；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项，两门课程与两个短训班对应关系不明确，可以理解为两个短训班都开设了这两门课程，也可以理解为数学班开设了农用数学课程、物理班开设了农业机电课程；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项，无歧义。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为D。</li></ol></details>',28)])])}const c=i(t,[["render",s]]);export{g as __pageData,c as default};
